files = [
    "src/layouts/components/Authors.astro",
    "src/layouts/components/Posts.astro",
    "src/layouts/components/Share.astro",
    "src/layouts/components/SimilarPosts.astro",
    "src/layouts/partials/Header.astro",
    "src/layouts/partials/PostSingle.astro",
    "src/pages/contact.astro",
    "src/pages/authors/[single].astro",
    "src/pages/categories/index.astro",
    "src/pages/tags/index.astro",
]

for fpath in files:
    with open(fpath, "r", encoding="utf-8") as f:
        content = f.read()

    # Remove ReactIconsWrapper import lines
    content = re.sub(
        r'import\s+\{[^}]+\}\s+from\s+["\']@/layouts/helpers/ReactIconsWrapper["\'];?\n?',
        "",
        content,
    )

    # Replace each icon JSX usage with its SVG
    for icon_name, svg in SVGS.items():
        # <IconName /> or <IconName/>
        content = re.sub(rf"<{icon_name}\s*/>", svg, content)
        # <IconName someProps /> (with attributes - drop the whole tag)
        content = re.sub(rf"<{icon_name}\s+[^>]*/>\s*", svg, content)

    with open(fpath, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"Fixed: {fpath}")

print("Done.")
